use std::collections::HashMap;

#[derive(Debug, Clone, Hash, Eq, PartialEq)]
pub enum OrderState {
    Pending,
    Confirmed,
    Shipped,
    Delivered,
    Cancelled,
}

#[derive(Debug, Clone, Hash, Eq, PartialEq)]
pub enum OrderEvent {
    Confirm,
    Ship,
    Deliver,
    Cancel,
}

pub struct StateMachine {
    current: OrderState,
    transitions: HashMap<(OrderState, OrderEvent), OrderState>,
}

impl StateMachine {
    pub fn new() -> Self {
        let mut transitions = HashMap::new();
        transitions.insert((OrderState::Pending, OrderEvent::Confirm), OrderState::Confirmed);
        transitions.insert((OrderState::Pending, OrderEvent::Cancel), OrderState::Cancelled);
        transitions.insert((OrderState::Confirmed, OrderEvent::Ship), OrderState::Shipped);
        transitions.insert((OrderState::Confirmed, OrderEvent::Cancel), OrderState::Cancelled);
        transitions.insert((OrderState::Shipped, OrderEvent::Deliver), OrderState::Delivered);

        Self { current: OrderState::Pending, transitions }
    }

    pub fn transition(&mut self, event: OrderEvent) -> Result<&OrderState, String> {
        let key = (self.current.clone(), event.clone());
        match self.transitions.get(&key) {
            Some(next) => {
                self.current = next.clone();
                Ok(&self.current)
            }
            None => Err(format!("Invalid transition: {:?} in state {:?}", event, self.current)),
        }
    }

    pub fn current_state(&self) -> &OrderState {
        &self.current
    }
}

from dataclasses import dataclass, field
from datetime import datetime
from typing import Any
import json

@dataclass(frozen=True)
class Event:
    event_type: str
    aggregate_id: str
    data: dict
    timestamp: datetime = field(default_factory=datetime.utcnow)
    version: int = 0

class EventStore:
    def __init__(self):
        self._events: list[Event] = []

    def append(self, event: Event) -> None:
        self._events.append(event)

    def get_events(self, aggregate_id: str) -> list[Event]:
        return [e for e in self._events if e.aggregate_id == aggregate_id]

class BankAccount:
    def __init__(self, account_id: str, event_store: EventStore):
        self._id = account_id
        self._store = event_store
        self._balance = 0.0
        self._replay()

    def deposit(self, amount: float) -> None:
        event = Event('deposited', self._id, {'amount': amount})
        self._store.append(event)
        self._apply(event)

    def withdraw(self, amount: float) -> None:
        if amount > self._balance:
            raise ValueError('Insufficient funds')
        event = Event('withdrawn', self._id, {'amount': amount})
        self._store.append(event)
        self._apply(event)

    def _apply(self, event: Event) -> None:
        if event.event_type == 'deposited':
            self._balance += event.data['amount']
        elif event.event_type == 'withdrawn':
            self._balance -= event.data['amount']

    def _replay(self) -> None:
        for event in self._store.get_events(self._id):
            self._apply(event)

    @property
    def balance(self) -> float:
        return self._balance
